const markWaitpointCheckpointFailed = `-- name: MarkWaitpointCheckpointFailed :one
WITH current_execution AS (
    SELECT runs.id AS run_id
      FROM runs
      JOIN run_executions ON run_executions.id = runs.current_execution_id
                          AND run_executions.org_id = runs.org_id
                          AND run_executions.run_id = runs.id
     WHERE runs.org_id = $1
       AND runs.id = $2
       AND runs.status = 'running'
       AND run_executions.id = $3
       AND run_executions.worker_instance_id = $4
       AND run_executions.status = 'running'
       AND run_executions.lease_expires_at > now()
),
target_run_wait AS (
    SELECT run_waits.id, run_waits.org_id, run_waits.run_id, run_waits.project_id, run_waits.environment_id, run_waits.execution_id, run_waits.checkpoint_id, run_waits.correlation_id, run_waits.status, run_waits.timeout_seconds, run_waits.policy_name, run_waits.policy_snapshot, run_waits.active_duration_ms, run_waits.failure, run_waits.resolution_kind, run_waits.resolution, run_waits.created_at, run_waits.waiting_at, run_waits.resolved_at, run_waits.restored_at, run_waits.failed_at, run_waits.updated_at
      FROM run_waits
      JOIN current_execution ON current_execution.run_id = run_waits.run_id
     WHERE run_waits.org_id = $1
       AND run_waits.id = $5
       AND run_waits.checkpoint_id = $6
       AND run_waits.execution_id = $3
       AND run_waits.status = 'opening'
     FOR UPDATE OF run_waits
),
failed_checkpoint AS (
    UPDATE checkpoints
       SET status = 'invalid',
           error_message = $7,
           invalidated_at = now()
      FROM target_run_wait
     WHERE checkpoints.org_id = $1
       AND checkpoints.run_id = target_run_wait.run_id
       AND checkpoints.id = target_run_wait.checkpoint_id
       AND checkpoints.execution_id = $3
       AND checkpoints.status = 'creating'
    RETURNING checkpoints.id, checkpoints.org_id, checkpoints.run_id, checkpoints.project_id, checkpoints.environment_id, checkpoints.execution_id, checkpoints.status, checkpoints.reason, checkpoints.manifest, checkpoints.error_message, checkpoints.created_at, checkpoints.ready_at, checkpoints.invalidated_at
),
failed_run_wait AS (
    UPDATE run_waits
       SET status = 'failed',
           failure = jsonb_build_object('reason', $7, 'source', 'checkpoint'),
           resolution_kind = 'cancelled',
           resolution = jsonb_build_object('reason', $7, 'source', 'checkpoint'),
           failed_at = now(),
           updated_at = now()
      FROM failed_checkpoint
     WHERE run_waits.org_id = $1
       AND run_waits.run_id = failed_checkpoint.run_id
       AND run_waits.id = $5
       AND run_waits.checkpoint_id = failed_checkpoint.id
       AND run_waits.execution_id = $3
       AND run_waits.status = 'opening'
    RETURNING run_waits.id, run_waits.org_id, run_waits.run_id, run_waits.project_id, run_waits.environment_id, run_waits.execution_id, run_waits.checkpoint_id, run_waits.correlation_id, run_waits.status, run_waits.timeout_seconds, run_waits.policy_name, run_waits.policy_snapshot, run_waits.active_duration_ms, run_waits.failure, run_waits.resolution_kind, run_waits.resolution, run_waits.created_at, run_waits.waiting_at, run_waits.resolved_at, run_waits.restored_at, run_waits.failed_at, run_waits.updated_at
),
cancelled_waitpoint AS (
    UPDATE waitpoints
       SET status = 'cancelled',
           resolution_kind = 'cancelled',
           output = 'null'::jsonb,
           resolution = jsonb_build_object('reason', $7, 'source', 'checkpoint'),
           output_is_error = true,
           completed_at = now(),
           updated_at = now()
      FROM failed_run_wait
      JOIN run_wait_dependencies ON run_wait_dependencies.org_id = failed_run_wait.org_id
                                AND run_wait_dependencies.run_wait_id = failed_run_wait.id
     WHERE waitpoints.org_id = run_wait_dependencies.org_id
       AND waitpoints.id = run_wait_dependencies.waitpoint_id
       AND waitpoints.status = 'pending'
    RETURNING waitpoints.id, waitpoints.org_id, waitpoints.project_id, waitpoints.environment_id, waitpoints.kind, waitpoints.request, waitpoints.display_text, waitpoints.status, waitpoints.output, waitpoints.resolution, waitpoints.output_is_error, waitpoints.resolution_kind, waitpoints.expires_at, waitpoints.idempotency_key, waitpoints.idempotency_request_hash, waitpoints.idempotency_key_expires_at, waitpoints.idempotency_key_options, waitpoints.created_at, waitpoints.completed_at, waitpoints.updated_at
),
selected_waitpoint AS (
    SELECT waitpoints.id, waitpoints.org_id, waitpoints.project_id, waitpoints.environment_id, waitpoints.kind, waitpoints.request, waitpoints.display_text, waitpoints.status, waitpoints.output, waitpoints.resolution, waitpoints.output_is_error, waitpoints.resolution_kind, waitpoints.expires_at, waitpoints.idempotency_key, waitpoints.idempotency_request_hash, waitpoints.idempotency_key_expires_at, waitpoints.idempotency_key_options, waitpoints.created_at, waitpoints.completed_at, waitpoints.updated_at
      FROM failed_run_wait
      JOIN run_wait_dependencies ON run_wait_dependencies.org_id = failed_run_wait.org_id
                                AND run_wait_dependencies.run_wait_id = failed_run_wait.id
      JOIN waitpoints ON waitpoints.org_id = run_wait_dependencies.org_id
                     AND waitpoints.id = run_wait_dependencies.waitpoint_id
                     AND waitpoints.id = $8
)
SELECT selected_waitpoint.id,
       failed_run_wait.id AS run_wait_id,
       selected_waitpoint.org_id,
       failed_run_wait.run_id,
       failed_run_wait.execution_id,
       failed_run_wait.checkpoint_id,
       failed_run_wait.correlation_id,
       selected_waitpoint.kind,
       selected_waitpoint.request,
       selected_waitpoint.display_text,
       failed_run_wait.timeout_seconds,
       failed_run_wait.policy_name,
       failed_run_wait.policy_snapshot,
       failed_run_wait.status,
       failed_run_wait.resolution_kind,
       failed_run_wait.resolution,
       selected_waitpoint.created_at,
       failed_run_wait.waiting_at AS requested_at,
       failed_run_wait.resolved_at
  FROM failed_run_wait
  JOIN selected_waitpoint ON true
`

